[?2004lEmitIR::operator()(FunctionDecl* obj)
{
  // Create function type
  std::vector<llvm::Type*> paramTypes;
  for (auto&& param : obj->params) {
    paramTypes.push_back(self(param->type));
  }

  auto retType = self(obj->type);
  auto funcType = llvm::FunctionType::get(retType, paramTypes, false);

  // Create function
  auto func = llvm::Function::Create(
    funcType, llvm::GlobalVariable::ExternalLinkage, obj->name, mMod);

  obj->any = func;

  if (obj->body == nullptr)
    return;

  auto entryBB = llvm::BasicBlock::Create(mCtx, "entry", func);
  mCurIrb->SetInsertPoint(entryBB);

  // Handle parameters
  auto argIt = func->arg_begin();
  for (auto&& param : obj->params) {
    auto paramAlloca = mCurIrb->CreateAlloca(argIt->getType(), nullptr, param->name);
    param->any = paramAlloca;
    mCurIrb->CreateStore(argIt, paramAlloca);
    argIt->setName(param->name);
    ++argIt;
  }

  // Translate function body
  mCurFunc = func;
  self(obj->body);

  // Add return if missing
  auto& exitIrb = *mCurIrb;
  if (exitIrb.GetInsertBlock()->getTerminator() == nullptr) {
    if (retType->isVoidTy()) {
      exitIrb.CreateRetVoid();
    } else {
      exitIrb.CreateUnreachable();
    }
  }
}
